import io.grpc.stub.StreamObserver;
import java.util.concurrent.*;
import java.util.*;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

public class TestStreamObserver<T> implements StreamObserver<T> {
    private final List<T> values = new CopyOnWriteArrayList<>();
    private Throwable error;
    private boolean completed = false;
    private final CountDownLatch done = new CountDownLatch(1);

    @Override
    public void onNext(T value) {
        values.add(value);
    }

    @Override
    public void onError(Throwable t) {
        this.error = t;
        done.countDown(); // stream ended (with error)
    }

    @Override
    public void onCompleted() {
        this.completed = true;
        done.countDown(); // stream ended (successfully)
    }

    public void awaitCompletion() throws InterruptedException {
        awaitCompletion(5, TimeUnit.SECONDS);
    }

    public void awaitCompletion(long timeout, TimeUnit unit) throws InterruptedException {
        assertTrue(done.await(timeout, unit),
            "Stream did not complete within " + timeout + " " + unit);
    }

    public List<T> getValues() { return Collections.unmodifiableList(values); }
    public Throwable getError() { return error; }
    public boolean hasError() { return error != null; }
    public boolean isCompleted() { return completed; }
    public int getValueCount() { return values.size(); }
}

@SpringBootTest
class TestStreamObserverTest {
    @Test void capturesValues() throws InterruptedException {
        TestStreamObserver<String> obs = new TestStreamObserver<>();
        obs.onNext("INITIATED");
        obs.onNext("PROCESSING");
        obs.onNext("CONFIRMED");
        obs.onCompleted();
        obs.awaitCompletion();
        assertEquals(3, obs.getValueCount());
        assertEquals("CONFIRMED", obs.getValues().get(2));
    }
    @Test void recordsError() throws InterruptedException {
        TestStreamObserver<String> obs = new TestStreamObserver<>();
        obs.onNext("INITIATED");
        obs.onError(new RuntimeException("Gateway timeout"));
        obs.awaitCompletion();
        assertTrue(obs.hasError());
        assertTrue(obs.getError().getMessage().contains("timeout"));
        assertFalse(obs.isCompleted()); // error, not normal completion
    }
    @Test void latch_releasedOnCompletion() throws InterruptedException {
        TestStreamObserver<Integer> obs = new TestStreamObserver<>();
        obs.onCompleted();
        obs.awaitCompletion(1, TimeUnit.SECONDS); // should not timeout
        assertTrue(obs.isCompleted());
    }
}

