@Service
class PaymentValidator {
    private static final long MAX_AMOUNT = 10_000_000L; // ₹1 lakh in paise
    private static final Set<String> KNOWN_MERCHANTS = Set.of("MRC-001", "MRC-002", "MRC-HDFC");

    public void validateAmount(long amountPaise) {
        if (amountPaise <= 0) throw new StatusRuntimeException(
            Status.INVALID_ARGUMENT.withDescription(
                "Amount must be positive, got: " + amountPaise + " paise"));
        if (amountPaise > MAX_AMOUNT) throw new StatusRuntimeException(
            Status.INVALID_ARGUMENT.withDescription(
                "Amount exceeds max " + MAX_AMOUNT + " paise (₹1 lakh), got: " + amountPaise));
    }

    public void validateMerchant(String merchantId) {
        if (!KNOWN_MERCHANTS.contains(merchantId)) throw new StatusRuntimeException(
            Status.NOT_FOUND.withDescription(
                "Merchant '" + merchantId + "' not found or inactive"));
    }
}

@SpringBootTest
class GrpcStatusExceptionTest {
    @Autowired PaymentValidator validator;

    @Test void zeroAmount_invalidArgument() {
        var ex = assertThrows(StatusRuntimeException.class, () -> validator.validateAmount(0));
        assertEquals(Status.Code.INVALID_ARGUMENT, ex.getStatus().getCode());
        assertTrue(ex.getStatus().getDescription().contains("positive"));
    }
    @Test void negativeAmount_invalidArgument() {
        var ex = assertThrows(StatusRuntimeException.class, () -> validator.validateAmount(-500));
        assertEquals(Status.Code.INVALID_ARGUMENT, ex.getStatus().getCode());
    }
    @Test void amountOverMax_invalidArgument() {
        var ex = assertThrows(StatusRuntimeException.class, () -> validator.validateAmount(10_000_001L));
        assertEquals(Status.Code.INVALID_ARGUMENT, ex.getStatus().getCode());
        assertTrue(ex.getStatus().getDescription().contains("max"));
    }
    @Test void unknownMerchant_notFound() {
        var ex = assertThrows(StatusRuntimeException.class, () -> validator.validateMerchant("MRC-UNKNOWN"));
        assertEquals(Status.Code.NOT_FOUND, ex.getStatus().getCode());
        assertTrue(ex.getStatus().getDescription().contains("MRC-UNKNOWN"));
    }
}

import io.grpc.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.Set;

// Test the interceptor logic directly:
@Service
class InterceptorTestHarness {
    private static final Metadata.Key<String> AUTH_KEY =
        Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER);
    private static final Set<String> VALID_TOKENS = Set.of(
        "rzp_test_valid_token", "hdfc_test_token"
    );

    // Simulate what the interceptor does:
    public AuthCheckResult checkAuth(Metadata headers) {
        String authHeader = headers.get(AUTH_KEY);
        if (authHeader == null)
            return AuthCheckResult.fail(Status.UNAUTHENTICATED.withDescription("Authorization header required"));
        if (!authHeader.startsWith("Bearer "))
            return AuthCheckResult.fail(Status.UNAUTHENTICATED.withDescription("Bearer format required"));
        String token = authHeader.substring(7);
        if (!VALID_TOKENS.contains(token))
            return AuthCheckResult.fail(Status.UNAUTHENTICATED.withDescription("Invalid token: " + token));
        return AuthCheckResult.pass(token);
    }

    record AuthCheckResult(boolean passed, Status failStatus, String token) {
        static AuthCheckResult pass(String t) { return new AuthCheckResult(true, null, t); }
        static AuthCheckResult fail(Status s) { return new AuthCheckResult(false, s, null); }
    }
}

@SpringBootTest
class InterceptorTest {
    @Autowired InterceptorTestHarness harness;

    @Test void noHeader_failsUnauthenticated() {
        Metadata headers = new Metadata();
        var result = harness.checkAuth(headers);
        assertFalse(result.passed());
        assertEquals(Status.Code.UNAUTHENTICATED, result.failStatus().getCode());
    }
    @Test void invalidToken_failsUnauthenticated() {
        Metadata headers = new Metadata();
        headers.put(Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER), "Bearer invalid_tok");
        var result = harness.checkAuth(headers);
        assertFalse(result.passed());
        assertTrue(result.failStatus().getDescription().contains("Invalid token"));
    }
    @Test void validToken_passes() {
        Metadata headers = new Metadata();
        headers.put(Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER), "Bearer rzp_test_valid_token");
        var result = harness.checkAuth(headers);
        assertTrue(result.passed());
        assertEquals("rzp_test_valid_token", result.token());
    }
}

import io.grpc.stub.StreamObserver;
import io.grpc.Status;
