import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.List;

@Service
class PaymentStatusStreamer {
    // Server-streaming: sends multiple status updates
    public void stream(String paymentId, StreamObserver<String> responseObserver) {
        if (paymentId == null || !paymentId.startsWith("PAY-")) {
            responseObserver.onError(new StatusRuntimeException(
                Status.NOT_FOUND.withDescription("Payment not found: " + paymentId)));
            return;
        }
        // Send status updates:
        responseObserver.onNext("INITIATED");
        responseObserver.onNext("PROCESSING");
        responseObserver.onNext("CONFIRMED");  // bug: was onError for amount > 10L
        responseObserver.onCompleted();
    }
}

@SpringBootTest
class StreamingRpcTest {
    @Autowired PaymentStatusStreamer streamer;

    @Test void happyPath_receivesAllStatuses() throws InterruptedException {
        TestStreamObserver<String> observer = new TestStreamObserver<>();
        streamer.stream("PAY-001", observer);
        observer.awaitCompletion();

        assertFalse(observer.hasError());
        assertTrue(observer.isCompleted());
        List<String> values = observer.getValues();
        assertEquals(3, values.size());
        assertEquals("INITIATED", values.get(0));
        assertEquals("PROCESSING", values.get(1));
        assertEquals("CONFIRMED", values.get(2));
    }

    @Test void invalidPaymentId_receivesError() throws InterruptedException {
        TestStreamObserver<String> observer = new TestStreamObserver<>();
        streamer.stream("INVALID-ID", observer);
        observer.awaitCompletion();

        assertTrue(observer.hasError());
        assertFalse(observer.isCompleted()); // completed vs error are mutually exclusive
        assertEquals(0, observer.getValueCount()); // no messages before error
    }
}

import io.grpc.stub.StreamObserver;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.List;

@Service
class EchoStreamService {
    // Bidirectional streaming: request observer receives client messages
    // Response observer sends back echoed messages
    public StreamObserver<String> bidiEcho(StreamObserver<String> responseObserver) {
        return new StreamObserver<>() {
            @Override
            public void onNext(String message) {
                responseObserver.onNext("ECHO: " + message); // echo back
            }
            @Override
            public void onError(Throwable t) {
                responseObserver.onError(t); // propagate errors
            }
            @Override
            public void onCompleted() {
                responseObserver.onCompleted(); // close response stream
            }
        };
    }
}

@SpringBootTest
class BidiStreamingTest {
    @Autowired EchoStreamService service;

    @Test void bidi_echosInOrder() throws InterruptedException {
        TestStreamObserver<String> responseObserver = new TestStreamObserver<>();

        // Get the request observer (what we use to send messages):
        StreamObserver<String> requestObserver = service.bidiEcho(responseObserver);

        // Send 3 messages:
        requestObserver.onNext("Hello");
        requestObserver.onNext("World");
        requestObserver.onNext("gRPC");
        requestObserver.onCompleted(); // done sending

        responseObserver.awaitCompletion();

        List<String> echoes = responseObserver.getValues();
        assertEquals(3, echoes.size());
        assertEquals("ECHO: Hello", echoes.get(0));
        assertEquals("ECHO: World", echoes.get(1));
        assertEquals("ECHO: gRPC", echoes.get(2));
    }

    @Test void bidi_clientError_propagated() throws InterruptedException {
        TestStreamObserver<String> responseObserver = new TestStreamObserver<>();
        StreamObserver<String> requestObserver = service.bidiEcho(responseObserver);

        requestObserver.onNext("First message");
        requestObserver.onError(new RuntimeException("Client disconnected")); // simulate client error

        responseObserver.awaitCompletion();
        assertTrue(responseObserver.hasError());
    }
}

