@Service
class GrpcAmountValidator {
    private static final long MIN = 1L;
    private static final long MAX = 10_000_000L; // ₹1 lakh in paise

    public void validate(long amountPaise) {
        if (amountPaise < MIN || amountPaise > MAX)
            throw new StatusRuntimeException(
                Status.INVALID_ARGUMENT.withDescription(
                    "Amount must be " + MIN + "–" + MAX + " paise, got: " + amountPaise));
    }
}

@SpringBootTest
class ParameterizedGrpcTest {
    @Autowired GrpcAmountValidator validator;

    static Stream<Long> invalidAmounts() {
        return Stream.of(0L, -1L, -1000L, 10_000_001L, Long.MAX_VALUE, Long.MIN_VALUE);
    }

    static Stream<Long> validAmounts() {
        return Stream.of(1L, 100L, 5000L, 50_000L, 5_00_000L, 10_000_000L);
    }

    @ParameterizedTest(name = "invalid amount={0} → INVALID_ARGUMENT")
    @MethodSource("invalidAmounts")
    void invalidAmount_throwsInvalidArgument(long amount) {
        var ex = assertThrows(StatusRuntimeException.class,
            () -> validator.validate(amount),
            "Expected INVALID_ARGUMENT for amount: " + amount);
        assertEquals(Status.Code.INVALID_ARGUMENT, ex.getStatus().getCode());
    }

    @ParameterizedTest(name = "valid amount={0} → passes")
    @MethodSource("validAmounts")
    void validAmount_passes(long amount) {
        assertDoesNotThrow(() -> validator.validate(amount),
            "Expected no exception for amount: " + amount);
    }
}

