import io.grpc.*;
import io.grpc.stub.StreamObserver;
import org.junit.jupiter.api.*;
import org.junit.jupiter.params.*;
import org.junit.jupiter.params.provider.*;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;
import java.util.stream.Stream;

class SynthGrpcService {
    public String echo(String msg){
        if(msg==null||msg.isBlank()) throw new StatusRuntimeException(Status.INVALID_ARGUMENT.withDescription("empty msg"));
        return "ECHO:"+msg;
    }
    public void streamNumbers(int count, StreamObserver<Integer> obs){
        if(count<=0){obs.onError(new StatusRuntimeException(Status.INVALID_ARGUMENT.withDescription("count must be positive")));return;}
        for(int i=1;i<=count;i++) obs.onNext(i);
        obs.onCompleted();
    }
}

class SynthAuthHarness {
    Set<String> tokens=Set.of("valid_tok");
    boolean isValid(String bearer){return bearer!=null&&bearer.startsWith("Bearer ")&&tokens.contains(bearer.substring(7));}
    void require(String b){if(!isValid(b)) throw new StatusRuntimeException(Status.UNAUTHENTICATED.withDescription("auth required"));}
}

class M28T5SynthesisTest {
    SynthGrpcService svc=new SynthGrpcService();
    SynthAuthHarness auth=new SynthAuthHarness();

    // Unary tests:
    @Test void echo_happyPath(){assertEquals("ECHO:Hello",svc.echo("Hello"));}
    @Test void echo_emptyThrows(){
        var ex=assertThrows(StatusRuntimeException.class,()->svc.echo(""));
        assertEquals(Status.Code.INVALID_ARGUMENT,ex.getStatus().getCode());
    }

    // Streaming test:
    @Test void streamNumbers_receivesAll() throws InterruptedException{
        TestStreamObserver<Integer> obs=new TestStreamObserver<>();
        svc.streamNumbers(3,obs);
        obs.awaitCompletion();
        assertEquals(List.of(1,2,3),obs.getValues());
    }

    // Auth test:
    @Test void invalidToken_unauthenticated(){
        var ex=assertThrows(StatusRuntimeException.class,()->auth.require("Bearer bad"));
        assertEquals(Status.Code.UNAUTHENTICATED,ex.getStatus().getCode());
    }

    // Parameterized:
    static Stream<String> invalidMessages(){return Stream.of("","   ",null);}
    @ParameterizedTest @MethodSource("invalidMessages")
    void echo_invalidInput_throwsInvalidArgument(String msg){
        assertThrows(StatusRuntimeException.class,()->svc.echo(msg));
    }
}
